const binaryKey = Object.keys(items[0].binary || {})[0];
const buffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);
const xml = buffer.toString('utf8');

const hosts = [];
const hostBlocks = xml.match(/<host[\s\S]*?<\/host>/g) || [];

for (const block of hostBlocks) {
  const ipMatch = block.match(/<address addr="([\d.]+)" addrtype="ipv4"/);
  if (!ipMatch) continue;
  const ip = ipMatch[1];

  const ports = [];
  const portBlocks = block.match(/<port[\s\S]*?<\/port>/g) || [];

  for (const port of portBlocks) {
    const stateMatch = port.match(/state state="(\w+)"/);
    if (!stateMatch || stateMatch[1] !== 'open') continue;

    const portidMatch = port.match(/portid="(\d+)"/);
    const serviceMatch = port.match(/<service name="([^"]+)"[^>]*product="([^"]*)"[^>]*version="([^"]*)"/);
    const serviceNameOnly = port.match(/<service name="([^"]+)"/);

    ports.push({
      port: portidMatch ? portidMatch[1] : 'unknown',
      service: serviceMatch ? serviceMatch[1] : (serviceNameOnly ? serviceNameOnly[1] : 'unknown'),
      product: serviceMatch ? serviceMatch[2] : '',
      version: serviceMatch ? serviceMatch[3] : ''
    });
  }

  hosts.push({ ip, ports });
}

if (hosts.length === 0) {
  return [{ json: { debug: true, xmlLength: xml.length, xmlPreview: xml.substring(0, 300) } }];
}

return hosts.flatMap(host =>
  host.ports.map(p => ({
    json: {
      ip: host.ip,
      port: p.port,
      service: p.service,
      product: p.product,
      version: p.version
    }
  }))
);

const results = [];

for (const item of items) {
  const vulns = item.json.vulnerabilities || [];

  for (const v of vulns) {
    const cve = v.cve;
    const cveId = cve.id || '';
    const description = (cve.descriptions || []).find(d => d.lang === 'en')?.value || '';

    let cvssScore = null;
    let severity = 'UNKNOWN';
    try {
      const metrics = cve.metrics?.cvssMetricV31?.[0]?.cvssData;
      if (metrics) {
        cvssScore = metrics.baseScore;
        severity = metrics.baseSeverity;
      }
    } catch(e) {}

    const claudePrompt = `CVE_REF:${cveId} | Description: ${description} | Severity: ${severity} | In 2-3 sentences: is this critical for a homelab? What is the recommended action?`;

    results.push({
      json: {
        cveId,
        description,
        cvssScore,
        severity,
        published: cve.published,
        claudePrompt,
        httpBody: JSON.stringify({
          model: "claude-haiku-4-5-20251001",
          max_tokens: 300,
          messages: [{ role: "user", content: claudePrompt }]
        })
      }
    });
  }
}

return results;

return items.map(item => {
  const text = item.json.content?.[0]?.text || 'No triage available';

  // Try to find CVE ID anywhere in the first 100 chars
  const cveMatch = text.match(/CVE-\d{4}-\d+/);
  const cveId = cveMatch ? cveMatch[0] : 'Unknown CVE';
  const triage = text.trim();

  return {
    json: { cveId, triage }
  };
});

const reportLines = [];

reportLines.push('# NullByte CVE Triage Report');
reportLines.push(`Generated: ${new Date().toISOString()}`);
reportLines.push('---');

for (const item of items) {
  const cveId = item.json.cveId || 'Unknown CVE';
  const triage = item.json.triage || 'No triage available';

  reportLines.push(`\n## ${cveId}`);
  reportLines.push(triage);
  reportLines.push('---');
}

const report = reportLines.join('\n');
const binary = Buffer.from(report, 'utf8').toString('base64');

return [{
  json: { fileName: 'nullbyte_report.md' },
  binary: {
    report: {
      data: binary,
      mimeType: 'text/markdown',
      fileName: 'nullbyte_report.md'
    }
  }
}];
